item.description:
Sobre linkO(n log n)
Link original: heapSort.cpp
Código link void down(vector&lt;int&gt;&amp; v, int n, int i) { while ((i = 2*i&#43;1) &lt; n) { if (i&#43;1 &lt; n and v[i] &lt; v[i&#43;1]) i&#43;&#43;; if (v[i] &lt; v[(i-1)/2]) break; swap(v[i], v[(i-1)/2]); } } void heap_sort(vector&lt;int&gt;&amp; v) { int n = v.size(); for (int i = n/2-1; i &gt;= 0; i--) down(v, n, i); for (int i = n-1; i &gt; 0; i--) swap(v[0], v[i]), down(v, i, 0); }

Sobre linkTudo O(1) amortizado
Link original: minqueueDeque.cpp
Código link template&lt;class T&gt; struct minqueue { deque&lt;pair&lt;T, int&gt;&gt; q; void push(T x) { int ct = 1; while (q.size() and x &lt; q.front().first) ct &#43;= q.front().second, q.pop_front(); q.emplace_front(x, ct); } void pop() { if (q.back().second &gt; 1) q.back().second--; else q.pop_back(); } T min() { return q.back().first; } };

Sobre linkO(1)
Link original: mulmod.cpp
Código link ll mul(ll a, ll b, ll m) { // a*b % m ll ret = a*b - ll((long double)1/m*a*b&#43;0.5)*m; return ret &lt; 0 ? ret&#43;m : ret; }

Sobre linkO(sqrt(n))
Link original: totiente.cpp
Código link int tot(int n) { int ret = n; for (int i = 2; i*i &lt;= n; i&#43;&#43;) if (n % i == 0) { while (n % i == 0) n /= i; ret -= ret / i; } if (n &gt; 1) ret -= ret / n; return ret; }
